  end

  it 'options_preprocessing_minimal: Minimal preset preserves nav, footer, aside' do
    result = HtmlToMarkdown.convert('<nav>Navigation</nav><p>Content</p><footer>Footer</footer>', HtmlToMarkdownRs::ConversionOptions.new(preprocessing: { 'preset' => 'Minimal' }))
    expect(result.content.to_s).to include('Navigation')
    expect(result.content.to_s).to include('Content')
    expect(result.content.to_s).to include('Footer')

  end

  it 'options_preprocessing_remove_forms: Forms are removed when remove_forms is true' do
    result = HtmlToMarkdown.convert("<p>Before</p><form><input type='text'/><button>Submit</button></form><p>After</p>", HtmlToMarkdownRs::ConversionOptions.new(preprocessing: { 'remove_forms' => true }))
    expect(result.content.to_s).to include('Before')
    expect(result.content.to_s).to include('After')
    expect(result.content.to_s).not_to include('Submit')

  end

  it 'options_preprocessing_remove_navigation_false_keeps_nav: Setting remove_navigation to false preserves nav and aside elements' do
    result = HtmlToMarkdown.convert('<nav>SiteMenu</nav><main><p>MainContent</p></main><aside>SidebarText</aside>', HtmlToMarkdownRs::ConversionOptions.new(preprocessing: { 'remove_navigation' => false }))
    expect(result.content.to_s).to include('SiteMenu')
    expect(result.content.to_s).to include('MainContent')
    expect(result.content.to_s).to include('SidebarText')

  end

  it 'options_preserve_tags_iframe: Iframe tags preserved as raw HTML in output' do
    result = HtmlToMarkdown.convert("<p>Before</p><iframe src='video.html' width='560'></iframe><p>After</p>", HtmlToMarkdownRs::ConversionOptions.new(preserve_tags: ['iframe']))
    expect(result.content.to_s).to include('Before')
    expect(result.content.to_s).to include('After')
    expect(result.content.to_s).to include('<iframe')

  end

  it 'options_skip_images_true: Images are omitted from output when skipImages is true' do
    result = HtmlToMarkdown.convert("<p>Before <img src='test.jpg' alt='photo'> After</p>", HtmlToMarkdownRs::ConversionOptions.new(skip_images: true))
    expect(result.content.to_s).to include('Before')
    expect(result.content.to_s).to include('After')
    expect(result.content.to_s).not_to include('photo')

  end

  it 'options_strip_newlines: Strip newlines produces single-line paragraphs' do
    result = HtmlToMarkdown.convert('<p>First paragraph.</p><p>Second paragraph.</p>', HtmlToMarkdownRs::ConversionOptions.new(strip_newlines: true))
    expect(result.content.to_s).to include('First paragraph.')
    expect(result.content.to_s).to include('Second paragraph.')

  end

  it 'options_strip_tags_div_span: Div and span tags stripped but content preserved' do
    result = HtmlToMarkdown.convert("<div class='wrapper'><p>Inside div</p></div><p>Outside <span class='hl'>span text</span></p>", HtmlToMarkdownRs::ConversionOptions.new(strip_tags: ['div', 'span']))
    expect(result.content.to_s).to include('Inside div')
    expect(result.content.to_s).to include('span text')

  end

  it 'options_strong_em_underscore: Strong and em tags use underscore symbol instead of asterisk' do
    result = HtmlToMarkdown.convert('<p><strong>bold</strong> and <em>italic</em></p>', HtmlToMarkdownRs::ConversionOptions.new(strong_em_symbol: '_'))
    expect(result.content.to_s).to include('__bold__')
    expect(result.content.to_s).to include('_italic_')

  end

  it 'options_sub_symbol_tilde: Subscript rendered with tilde symbol' do
    result = HtmlToMarkdown.convert('<p>H<sub>2</sub>O</p>', HtmlToMarkdownRs::ConversionOptions.new(sub_symbol: '~'))
    expect(result.content.to_s).to include('~2~')

  end

  it 'options_sup_symbol_caret: Superscript rendered with caret symbol' do
    result = HtmlToMarkdown.convert('<p>x<sup>2</sup></p>', HtmlToMarkdownRs::ConversionOptions.new(sup_symbol: '^'))
    expect(result.content.to_s).to include('^2^')

  end

  it 'options_url_escape_style_angle_default: Default angle style wraps URLs containing spaces in angle brackets' do
    result = HtmlToMarkdown.convert('<a href="/file (1).pdf">file</a>', HtmlToMarkdownRs::ConversionOptions.new(url_escape_style: 'angle'))
    expect(result.content.to_s).to include('</file (1).pdf>')

  end

  it 'options_url_escape_style_percent_angle_brackets_in_url: Percent style encodes angle brackets in link URLs from issue 392' do
    result = HtmlToMarkdown.convert('<a href="/file (1) <draft>.pdf">file</a>', HtmlToMarkdownRs::ConversionOptions.new(url_escape_style: 'percent'))
    expect(result.content.to_s).to include('/file%20%281%29%20%3Cdraft%3E.pdf')

  end

  it 'options_url_escape_style_percent_image: Percent style encodes special characters in image src URLs' do
    result = HtmlToMarkdown.convert('<img src="/img (1) <draft>.png" alt="alt">', HtmlToMarkdownRs::ConversionOptions.new(url_escape_style: 'percent'))
    expect(result.content.to_s).to include('/img%20%281%29%20%3Cdraft%3E.png')

  end

  it 'options_url_escape_style_percent_link: Percent style encodes spaces and parens in link URLs' do
    result = HtmlToMarkdown.convert('<a href="/file (1).pdf">file</a>', HtmlToMarkdownRs::ConversionOptions.new(url_escape_style: 'percent'))
    expect(result.content.to_s).to include('/file%20%281%29.pdf')
    expect(result.content.to_s).not_to include('</')

  end

  it 'options_whitespace_normalized: Normalized whitespace mode collapses multiple spaces' do
    result = HtmlToMarkdown.convert('<p>Text   with    extra   spaces.</p>', HtmlToMarkdownRs::ConversionOptions.new(whitespace_mode: 'Normalized'))
    expect(result.content.to_s).not_to be_empty
    expect(result.content.to_s).to include('Text')
    expect(result.content.to_s).to include('with')
    expect(result.content.to_s).to include('extra')
    expect(result.content.to_s).to include('spaces.')

  end

  it 'options_whitespace_strict: Strict whitespace mode preserves whitespace as-is' do
    result = HtmlToMarkdown.convert('<p>Preserved   spacing.</p>', HtmlToMarkdownRs::ConversionOptions.new(whitespace_mode: 'Strict'))
    expect(result.content.to_s).not_to be_empty
    expect(result.content.to_s).to include('Preserved')
    expect(result.content.to_s).to include('spacing.')

  end

  it 'options_wrap_disabled: Wrap option disabled preserves long lines without breaking' do
    result = HtmlToMarkdown.convert('<p>This is a long paragraph that should not be wrapped at all because wrapping is disabled.</p>', HtmlToMarkdownRs::ConversionOptions.new(wrap: false))
    expect(result.content.to_s).to include('This is a long paragraph that should not be wrapped at all because wrapping is disabled.')

  end

  it 'options_wrap_enabled: Wrap option enabled with custom width wraps long lines' do
    result = HtmlToMarkdown.convert('<p>This is a long paragraph that should be wrapped at the specified column width when the wrap option is enabled.</p>', HtmlToMarkdownRs::ConversionOptions.new(wrap: true, wrap_width: 40))
    expect(result.content.to_s).not_to be_empty
    expect(result.content.to_s).to include('This is a long paragraph')

  end
end
